import{c as r,Q as e,j as o,m as a}from"./chunks/framework.rlpw0eGz.js";const p=JSON.parse('{"title":"MCP 连接","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/mcp.md","filePath":"zh/getting-started/mcp.md","lastUpdated":1777012567000}'),n={name:"zh/getting-started/mcp.md"};function d(s,t,h,i,l,g){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="mcp-连接" tabindex="-1">MCP 连接 <a class="header-anchor" href="#mcp-连接" aria-label="Permalink to &quot;MCP 连接&quot;">​</a></h1><p>Memoh 支持 <strong>Model Context Protocol (MCP)</strong>，让机器人接外部工具与上下文服务。每个机器人可以有自己的一组 MCP 连接。</p><h2 id="在做什么" tabindex="-1">在做什么 <a class="header-anchor" href="#在做什么" aria-label="Permalink to &quot;在做什么&quot;">​</a></h2><p>MCP 把「外部数据、外部工具」用相对统一的方式接进来。你在机器人 <strong>MCP</strong> tab 里手配，或从 <a href="/zh/getting-started/supermarket.html">超市</a> 装模板再进编辑器改。</p><hr><h2 id="连接类型" tabindex="-1">连接类型 <a class="header-anchor" href="#连接类型" aria-label="Permalink to &quot;连接类型&quot;">​</a></h2><h3 id="_1-stdio-本机进程" tabindex="-1">1. Stdio（本机进程） <a class="header-anchor" href="#_1-stdio-本机进程" aria-label="Permalink to &quot;1. Stdio（本机进程）&quot;">​</a></h3><p>在机器人<strong>容器里</strong>起本地命令，用标准输入输出通信。</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>Command</strong></td><td>可执行文件，如 <code>npx</code>、<code>python3</code></td></tr><tr><td><strong>Arguments</strong></td><td>参数列表</td></tr><tr><td><strong>Env</strong></td><td>环境变量</td></tr><tr><td><strong>CWD</strong></td><td>工作目录</td></tr></tbody></table><h3 id="_2-remote-http-sse" tabindex="-1">2. Remote（HTTP/SSE） <a class="header-anchor" href="#_2-remote-http-sse" aria-label="Permalink to &quot;2. Remote（HTTP/SSE）&quot;">​</a></h3><p>走网络的远程 MCP。</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>URL</strong></td><td>服务端点</td></tr><tr><td><strong>Headers</strong></td><td>如鉴权头</td></tr><tr><td><strong>Transport</strong></td><td><code>http</code> 或 <code>sse</code></td></tr></tbody></table><hr><h2 id="oauth" tabindex="-1">OAuth <a class="header-anchor" href="#oauth" aria-label="Permalink to &quot;OAuth&quot;">​</a></h2><p>有的 MCP 服要走 OAuth。Memoh 会：</p><ol><li>在需要认证的连接上点 <strong>OAuth</strong>。</li><li>自动 <strong>discover</strong> 服务方 OAuth 配置。</li><li><strong>Authorize</strong> 打开授权页。</li><li>用户同意后回跳，Memoh <strong>换 token</strong> 并安全存好。</li></ol><p>也可看状态、<strong>Revoke</strong> 清掉 token。</p><hr><h2 id="操作" tabindex="-1">操作 <a class="header-anchor" href="#操作" aria-label="Permalink to &quot;操作&quot;">​</a></h2><ul><li><strong>Add Connection</strong>：加一条，选类型，填表。</li><li><strong>Import JSON</strong>：从标准 <code>mcpServers</code> JSON 一次导入多条。</li><li><strong>Export</strong>：导出备份或分享。</li><li><strong>Toggle Active</strong>：不删，只开/关某条。</li><li><strong>Search</strong>：按名或 id 找。</li><li><strong>Batch Delete</strong>：多选删除。</li></ul><hr><h2 id="工具发现" tabindex="-1">工具发现 <a class="header-anchor" href="#工具发现" aria-label="Permalink to &quot;工具发现&quot;">​</a></h2><p>连接 active 后，Memoh 会拉该服暴露的工具。点进连接可看 <strong>Tools</strong> 列表。需要时点 <strong>Probe</strong> 手动刷新。</p><hr><h2 id="和机器人怎么配合" tabindex="-1">和机器人怎么配合 <a class="header-anchor" href="#和机器人怎么配合" aria-label="Permalink to &quot;和机器人怎么配合&quot;">​</a></h2><p>连上后，对话里模型会按说明选用这些工具；发现到的工具会进推理流程。具体工具名、参数以服端为准。</p>',26)])])}const m=r(n,[["render",d]]);export{p as __pageData,m as default};
